   114→
   115→    // Declare serialVersionUID to be compatible with JDK1.1
   116→    @java.io.Serial
   117→    private static final long serialVersionUID = -4298000515446427739L;
   118→
   119→    private static final sun.security.util.Debug debug =
   120→        sun.security.util.Debug.getInstance("provider", "Provider");
   121→
   122→    /**
   123→     * The provider name.
   124→     *
   125→     * @serial
   126→     */
   127→    private final String name;
   128→
   129→    /**
   130→     * A description of the provider and its services.
   131→     *
   132→     * @serial
   133→     */
   134→    private final String info;
   135→
   136→    /**
   137→     * The provider version number.
   138→     *
   139→     * @serial
   140→     */
   141→    private double version;
   142→
   143→    /**
   144→     * The provider version string.
   145→     *
   146→     * @serial
   147→     */
   148→    private String versionStr;
   149→
   150→    private transient Set<Map.Entry<Object,Object>> entrySet = null;
   151→    private transient int entrySetCallCount = 0;
   152→
   153→    private transient boolean initialized;
   154→
   155→    private static final Object[] EMPTY = new Object[0];
   156→
   157→    private static double parseVersionStr(String s) {
   158→        try {
   159→            int firstDotIdx = s.indexOf('.');
   160→            int nextDotIdx = s.indexOf('.', firstDotIdx + 1);
   161→            if (nextDotIdx != -1) {
   162→                s = s.substring(0, nextDotIdx);
   163→            }
   164→            int endIdx = s.indexOf('-');
   165→            if (endIdx > 0) {
   166→                s = s.substring(0, endIdx);
   167→            }
   168→            endIdx = s.indexOf('+');
   169→            if (endIdx > 0) {
   170→                s = s.substring(0, endIdx);
   171→            }
   172→            return Double.parseDouble(s);
   173→        } catch (NullPointerException | NumberFormatException e) {
   174→            return 0d;
   175→        }
   176→    }
   177→
   178→    /**
